%[text] # Missions
s = uint8(zeros(100,100,3));
s(1:50, 1:50, 1) = 255; %행, 열의 1부터 50까지를 1번인 red(r:1 g:2 b:3)로 채워라(0부터 255)
s(1:50, 51:end, 2) = 255; %행의 1부터 50까지, 열의 51부터 100까지를 2번인 green으로 채워라
s(51:end, 1:50, 3) = 255; %행의 51부터 100까지, 열의 1부터 50까지를 3번인 blue으로 채워라
figure(1), imshow(s); %[output:73a9a4ac]
%[text] ## Mission 3a - Tricolour, the Flag of France
F = uint8(zeros(200, 300, 3));
%part blue
blue = [0 85 164];
F(1:end,1:100,1) = blue(1);
F(1:end,1:100,2) = blue(2);
F(1:end,1:100,3) = blue(3);
%part white
white = [255 255 255];
F(1:end, 101:200,1) = white(1);
F(1:end, 101:200,2) = white(2);
F(1:end, 101:200,3) = white(3);
%part red
red = [250 60 50];
F(1:end, 200:end,1) = red(1);
F(1:end, 200:end,2) = red(2);
F(1:end, 200:end,3) = red(3);
figure(2), imshow(F); %[output:22490d83]
%%
%[text] ## Mission 3b - Olaf Loves Summer
C = imread('olaf.png');
figure(3), imshow(C); %[output:5a6adfe9]

%Retouch the Color to Summer feel, red 3 times, blue 0.5 times
M = C;
M(:,:,1) = M(:,:,1) * 3; %M(:,:,1)을 red 3배 한 것으로 재정의
M(:,:,3) = M(:,:,3) * 0.5; %M(:,:,3)을 blue 3배 한 것으로 재정의
figure(4), imshow(M); %[output:0de8e996]
%%
%[text] ## Example1 - Color Photo Frame
Fe = imread('ferrari1.png'); %페라리 사진 불러오가
figure(5), imshow(Fe); %figure(5)로 보이기 %[output:0aea22fa]
[m,n,k] = size(Fe); %페라리 사진의 사이즈(정보)를 m: 행, n: 열, k: rgb 초기화
% Create frame around the img 
Fr = uint8(zeros(m+40, n+40, k)); %프레임의 사이즈: 열: 페라리 +40, 행: 페라리 +40
[m1, n1, k1] = size(Fr); %프레임 사이즈를 m1, n1, k1으로 재정의
Fr(21:m+20, 21:n+20,:) = Fe; %프레임의 상하좌우 각 20씩 안에 페라리 사진 넣기

% 상단 프레임 r
% 행렬을 복사하여 [20 n1]로 만들기 / mod = c언어 %
% 0부터 n1-1까지의 수를 256()~255)으로 나눈 수의 나머지는 그라디언트로 표현됨
Fr(1:20, :, 1) = repmat(mod(0:n1-1, 256), 20, 1);

%하단 프레임 g
% 행렬을 복사하여 [20 n1]로 만들기 / mod = c언어 %
% 0부터 n1-1까지의 수를 256()~255)으로 나눈 수의 나머지는 그라디언트로 표현됨 +125로 우측으로 125만큼 보냄
Fr(end-19:end, :, 2) = repmat(mod((0:n1-1) +125, 256), 20, 1);

%좌측 프레임 r
% 행렬을 복사하여 [m1 20]로 만들기 / mod = c언어 %
% m1-1부터 0까지의 수를 -m1을 해준 뒤 (시작이 밝아야 하니까) 역행렬(열로 만들기)
%  256(0~255)으로 나눈 수(나머지 양수)의 나머지는 그라디언트로 표현됨
Fr(:, 1:20, 1) = repmat(mod(((m1-1:-1:0)-m1)',256), 1, 20);

%우측 프레임 b
% 행렬을 복사하여 [m1 20]로 만들기 / mod = c언어 %
% m1-1부터 0까지의 수를 -m1을 해준 뒤 (시작이 밝아야 하니까) 역행렬(열로 만들기)
%  256(0~255)으로 나눈 수(나머지 양수)의 나머지는 그라디언트로 표현됨
Fr(:, end-19: end, 3) = repmat(mod(((m1-1:-1:0)-m1)', 256), 1, 20);

figure(6), imshow(Fr); %[output:3d87b011]
imwrite(Fe, 'framed.jpg');
%[text] 
%%
%[text] ## Mission 3c - Frozen Puzzle


